#endif

typedef enum {
    QJS_AUTOINIT_ID_PROTOTYPE,
    QJS_AUTOINIT_ID_MODULE_NS,
    QJS_AUTOINIT_ID_PROP,
} QJSAutoInitIDEnum;

/* must be large enough to have a negligible runtime cost and small
   enough to call the interrupt callback often. */
#define QJS_INTERRUPT_COUNTER_INIT 10000

struct QJSContext {
    QJSGCObjectHeader header; /* must come first */
    QJSRuntime *rt;
    struct list_head link;

    uint16_t binary_object_count;
    int binary_object_size;

    QJSShape *array_shape;   /* initial shape for Array objects */

    QJSValue *class_proto;
    QJSValue function_proto;
    QJSValue function_ctor;
    QJSValue array_ctor;
    QJSValue regexp_ctor;
    QJSValue promise_ctor;
    QJSValue native_error_proto[QJS_NATIVE_ERROR_COUNT];
    QJSValue iterator_proto;
    QJSValue async_iterator_proto;
    QJSValue array_proto_values;
    QJSValue throw_type_error;
    QJSValue eval_obj;

    QJSValue global_obj; /* global object */
    QJSValue global_var_obj; /* contains the global let/const definitions */

    uint64_t random_state;
#ifdef CONFIG_BIGNUM
    bf_context_t *bf_ctx;   /* points to rt->bf_ctx, shared by all contexts */
    QJSFloatEnv fp_env; /* global FP environment */
    BOOL bignum_ext : 8; /* enable math mode */
    BOOL allow_operator_overloading : 8;
#endif
    /* when the counter reaches zero, QJSRutime.interrupt_handler is called */
    int interrupt_counter;
    BOOL is_error_property_enabled;

    struct list_head loaded_modules; /* list of QJSModuleDef.link */

    /* if NULL, RegExp compilation is not supported */
    QJSValue (*compile_regexp)(QJSContext *ctx, QJSValueConst pattern,
                              QJSValueConst flags);
    /* if NULL, eval is not supported */
    QJSValue (*eval_internal)(QJSContext *ctx, QJSValueConst this_obj,
                             const char *input, size_t input_len,
                             const char *filename, int flags, int scope_idx);
    void *user_opaque;
};

