/* return an empty string if not an object */
static QJSValue js_object___getClass(QJSContext *ctx, QJSValueConst this_val,
                                    int argc, QJSValueConst *argv)
{
    QJSAtom atom;
    QJSObject *p;
    uint32_t tag;
    int class_id;

    tag = QJS_VALUE_GET_NORM_TAG(argv[0]);
    if (tag == QJS_TAG_OBJECT) {
        p = QJS_VALUE_GET_OBJ(argv[0]);
        class_id = p->class_id;
        if (class_id == QJS_CLASS_PROXY && QJS_IsFunction(ctx, argv[0]))
            class_id = QJS_CLASS_BYTECODE_FUNCTION;
        atom = ctx->rt->class_array[class_id].class_name;
    } else {
        atom = QJS_ATOM_empty_string;
    }
    return QJS_AtomToString(ctx, atom);
}

