static QJSValue QJS_SpeciesConstructor(QJSContext *ctx, QJSValueConst obj,
                                     QJSValueConst defaultConstructor)
{
    QJSValue ctor, species;

    if (!QJS_IsObject(obj))
        return QJS_ThrowTypeErrorNotAnObject(ctx);
    ctor = QJS_GetProperty(ctx, obj, QJS_ATOM_constructor);
    if (QJS_IsException(ctor))
        return ctor;
    if (QJS_IsUndefined(ctor))
        return QJS_DupValue(ctx, defaultConstructor);
    if (!QJS_IsObject(ctor)) {
        QJS_FreeValue(ctx, ctor);
        return QJS_ThrowTypeErrorNotAnObject(ctx);
    }
    species = QJS_GetProperty(ctx, ctor, QJS_ATOM_Symbol_species);
    QJS_FreeValue(ctx, ctor);
    if (QJS_IsException(species))
        return species;
    if (QJS_IsUndefined(species) || QJS_IsNull(species))
        return QJS_DupValue(ctx, defaultConstructor);
    if (!QJS_IsConstructor(ctx, species)) {
        QJS_FreeValue(ctx, species);
        return QJS_ThrowTypeError(ctx, "not a constructor");
    }
    return species;
}

