/* Number */

static QJSValue js_number_constructor(QJSContext *ctx, QJSValueConst new_target,
                                     int argc, QJSValueConst *argv)
{
    QJSValue val, obj;
    if (argc == 0) {
        val = QJS_NewInt32(ctx, 0);
    } else {
        val = QJS_ToNumeric(ctx, argv[0]);
        if (QJS_IsException(val))
            return val;
        switch(QJS_VALUE_GET_TAG(val)) {
#ifdef CONFIG_BIGNUM
        case QJS_TAG_BIG_INT:
        case QJS_TAG_BIG_FLOAT:
            {
                QJSBigFloat *p = QJS_VALUE_GET_PTR(val);
                double d;
                bf_get_float64(&p->num, &d, BF_RNDN);
                QJS_FreeValue(ctx, val);
                val = __JS_NewFloat64(ctx, d);
            }
            break;
        case QJS_TAG_BIG_DECIMAL:
            val = QJS_ToStringFree(ctx, val);
            if (QJS_IsException(val))
                return val;
            val = QJS_ToNumberFree(ctx, val);
            if (QJS_IsException(val))
                return val;
            break;
#endif
        default:
            break;
        }
    }
    if (!QJS_IsUndefined(new_target)) {
        obj = js_create_from_ctor(ctx, new_target, QJS_CLASS_NUMBER);
        if (!QJS_IsException(obj))
            QJS_SetObjectData(ctx, obj, val);
        return obj;
    } else {
        return val;
    }
}

