static QJSValue js_thisNumberValue(QJSContext *ctx, QJSValueConst this_val)
{
    if (QJS_IsNumber(this_val))
        return QJS_DupValue(ctx, this_val);

    if (QJS_VALUE_GET_TAG(this_val) == QJS_TAG_OBJECT) {
        QJSObject *p = QJS_VALUE_GET_OBJ(this_val);
        if (p->class_id == QJS_CLASS_NUMBER) {
            if (QJS_IsNumber(p->u.object_data))
                return QJS_DupValue(ctx, p->u.object_data);
        }
    }
    return QJS_ThrowTypeError(ctx, "not a number");
}

static QJSValue js_number_valueOf(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv)
{
    return js_thisNumberValue(ctx, this_val);
}

static int js_get_radix(QJSContext *ctx, QJSValueConst val)
{
    int radix;
    if (QJS_ToInt32Sat(ctx, &radix, val))
        return -1;
    if (radix < 2 || radix > 36) {
        QJS_ThrowRangeError(ctx, "radix must be between 2 and 36");
        return -1;
    }
    return radix;
}

static QJSValue js_number_toString(QJSContext *ctx, QJSValueConst this_val,
                                  int argc, QJSValueConst *argv, int magic)
{
    QJSValue val;
    int base;
    double d;

    val = js_thisNumberValue(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    if (magic || QJS_IsUndefined(argv[0])) {
        base = 10;
    } else {
        base = js_get_radix(ctx, argv[0]);
        if (base < 0)
            goto fail;
    }
    if (QJS_ToFloat64Free(ctx, &d, val))
        return QJS_EXCEPTION;
    return js_dtoa(ctx, d, base, 0, QJS_DTOA_VAR_FORMAT);
 fail:
    QJS_FreeValue(ctx, val);
    return QJS_EXCEPTION;
}

static QJSValue js_number_toFixed(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv)
{
    QJSValue val;
    int f;
    double d;

    val = js_thisNumberValue(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    if (QJS_ToFloat64Free(ctx, &d, val))
        return QJS_EXCEPTION;
    if (QJS_ToInt32Sat(ctx, &f, argv[0]))
        return QJS_EXCEPTION;
    if (f < 0 || f > 100)
        return QJS_ThrowRangeError(ctx, "invalid number of digits");
    if (fabs(d) >= 1e21) {
        return QJS_ToStringFree(ctx, __JS_NewFloat64(ctx, d));
    } else {
        return js_dtoa(ctx, d, 10, f, QJS_DTOA_FRAC_FORMAT);
    }
}

static QJSValue js_number_toExponential(QJSContext *ctx, QJSValueConst this_val,
                                       int argc, QJSValueConst *argv)
{
    QJSValue val;
    int f, flags;
    double d;

    val = js_thisNumberValue(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    if (QJS_ToFloat64Free(ctx, &d, val))
        return QJS_EXCEPTION;
    if (QJS_ToInt32Sat(ctx, &f, argv[0]))
        return QJS_EXCEPTION;
    if (!isfinite(d)) {
        return QJS_ToStringFree(ctx,  __JS_NewFloat64(ctx, d));
    }
    if (QJS_IsUndefined(argv[0])) {
        flags = 0;
        f = 0;
    } else {
        if (f < 0 || f > 100)
            return QJS_ThrowRangeError(ctx, "invalid number of digits");
        f++;
        flags = QJS_DTOA_FIXED_FORMAT;
    }
    return js_dtoa(ctx, d, 10, f, flags | QJS_DTOA_FORCE_EXP);
}

static QJSValue js_number_toPrecision(QJSContext *ctx, QJSValueConst this_val,
                                     int argc, QJSValueConst *argv)
{
    QJSValue val;
    int p;
    double d;

    val = js_thisNumberValue(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    if (QJS_ToFloat64Free(ctx, &d, val))
        return QJS_EXCEPTION;
    if (QJS_IsUndefined(argv[0]))
        goto to_string;
    if (QJS_ToInt32Sat(ctx, &p, argv[0]))
        return QJS_EXCEPTION;
    if (!isfinite(d)) {
    to_string:
        return QJS_ToStringFree(ctx,  __JS_NewFloat64(ctx, d));
    }
    if (p < 1 || p > 100)
        return QJS_ThrowRangeError(ctx, "invalid number of digits");
    return js_dtoa(ctx, d, 10, p, QJS_DTOA_FIXED_FORMAT);
}

