static QJSValue js_parseInt(QJSContext *ctx, QJSValueConst this_val,
                           int argc, QJSValueConst *argv)
{
    const char *str, *p;
    int radix, flags;
    QJSValue ret;

    str = QJS_ToCString(ctx, argv[0]);
    if (!str)
        return QJS_EXCEPTION;
    if (QJS_ToInt32(ctx, &radix, argv[1])) {
        QJS_FreeCString(ctx, str);
        return QJS_EXCEPTION;
    }
    if (radix != 0 && (radix < 2 || radix > 36)) {
        ret = QJS_NAN;
    } else {
        p = str;
        p += skip_spaces(p);
        flags = ATOD_INT_ONLY | ATOD_ACCEPT_PREFIX_AFTER_SIGN;
        ret = js_atof(ctx, p, NULL, radix, flags);
    }
    QJS_FreeCString(ctx, str);
    return ret;
}

static QJSValue js_parseFloat(QJSContext *ctx, QJSValueConst this_val,
                             int argc, QJSValueConst *argv)
{
    const char *str, *p;
    QJSValue ret;

    str = QJS_ToCString(ctx, argv[0]);
    if (!str)
        return QJS_EXCEPTION;
    p = str;
    p += skip_spaces(p);
    ret = js_atof(ctx, p, NULL, 10, 0);
    QJS_FreeCString(ctx, str);
    return ret;
}

/* Boolean */
static QJSValue js_boolean_constructor(QJSContext *ctx, QJSValueConst new_target,
                                     int argc, QJSValueConst *argv)
{
    QJSValue val, obj;
    val = QJS_NewBool(ctx, QJS_ToBool(ctx, argv[0]));
    if (!QJS_IsUndefined(new_target)) {
        obj = js_create_from_ctor(ctx, new_target, QJS_CLASS_BOOLEAN);
        if (!QJS_IsException(obj))
            QJS_SetObjectData(ctx, obj, val);
        return obj;
    } else {
        return val;
    }
}

static QJSValue js_thisBooleanValue(QJSContext *ctx, QJSValueConst this_val)
{
    if (QJS_VALUE_GET_TAG(this_val) == QJS_TAG_BOOL)
        return QJS_DupValue(ctx, this_val);

    if (QJS_VALUE_GET_TAG(this_val) == QJS_TAG_OBJECT) {
        QJSObject *p = QJS_VALUE_GET_OBJ(this_val);
        if (p->class_id == QJS_CLASS_BOOLEAN) {
            if (QJS_VALUE_GET_TAG(p->u.object_data) == QJS_TAG_BOOL)
                return p->u.object_data;
        }
    }
    return QJS_ThrowTypeError(ctx, "not a boolean");
}

static QJSValue js_boolean_toString(QJSContext *ctx, QJSValueConst this_val,
                                   int argc, QJSValueConst *argv)
{
    QJSValue val = js_thisBooleanValue(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    return QJS_AtomToString(ctx, QJS_VALUE_GET_BOOL(val) ?
                       QJS_ATOM_true : QJS_ATOM_false);
}

static QJSValue js_boolean_valueOf(QJSContext *ctx, QJSValueConst this_val,
                                  int argc, QJSValueConst *argv)
{
    return js_thisBooleanValue(ctx, this_val);
}

