static QJSValue js_string_charCodeAt(QJSContext *ctx, QJSValueConst this_val,
                                     int argc, QJSValueConst *argv)
{
    QJSValue val, ret;
    QJSString *p;
    int idx, c;

    val = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    p = QJS_VALUE_GET_STRING(val);
    if (QJS_ToInt32Sat(ctx, &idx, argv[0])) {
        QJS_FreeValue(ctx, val);
        return QJS_EXCEPTION;
    }
    if (idx < 0 || idx >= p->len) {
        ret = QJS_NAN;
    } else {
        if (p->is_wide_char)
            c = p->u.str16[idx];
        else
            c = p->u.str8[idx];
        ret = QJS_NewInt32(ctx, c);
    }
    QJS_FreeValue(ctx, val);
    return ret;
}

static QJSValue js_string_charAt(QJSContext *ctx, QJSValueConst this_val,
                                int argc, QJSValueConst *argv)
{
    QJSValue val, ret;
    QJSString *p;
    int idx, c;

    val = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    p = QJS_VALUE_GET_STRING(val);
    if (QJS_ToInt32Sat(ctx, &idx, argv[0])) {
        QJS_FreeValue(ctx, val);
        return QJS_EXCEPTION;
    }
    if (idx < 0 || idx >= p->len) {
        ret = js_new_string8(ctx, NULL, 0);
    } else {
        if (p->is_wide_char)
            c = p->u.str16[idx];
        else
            c = p->u.str8[idx];
        ret = js_new_string_char(ctx, c);
    }
    QJS_FreeValue(ctx, val);
    return ret;
}

static QJSValue js_string_codePointAt(QJSContext *ctx, QJSValueConst this_val,
                                     int argc, QJSValueConst *argv)
{
    QJSValue val, ret;
    QJSString *p;
    int idx, c;

    val = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    p = QJS_VALUE_GET_STRING(val);
    if (QJS_ToInt32Sat(ctx, &idx, argv[0])) {
        QJS_FreeValue(ctx, val);
        return QJS_EXCEPTION;
    }
    if (idx < 0 || idx >= p->len) {
        ret = QJS_UNDEFINED;
    } else {
        c = string_getc(p, &idx);
        ret = QJS_NewInt32(ctx, c);
    }
    QJS_FreeValue(ctx, val);
    return ret;
}

static QJSValue js_string_concat(QJSContext *ctx, QJSValueConst this_val,
                                int argc, QJSValueConst *argv)
{
    QJSValue r;
    int i;

    /* XXX: Use more efficient method */
    /* XXX: This method is OK if r has a single refcount */
    /* XXX: should use string_buffer? */
    r = QJS_ToStringCheckObject(ctx, this_val);
    for (i = 0; i < argc; i++) {
        if (QJS_IsException(r))
            break;
        r = QJS_ConcatString(ctx, r, QJS_DupValue(ctx, argv[i]));
    }
    return r;
}

static int string_cmp(QJSString *p1, QJSString *p2, int x1, int x2, int len)
{
    int i, c1, c2;
    for (i = 0; i < len; i++) {
        if ((c1 = string_get(p1, x1 + i)) != (c2 = string_get(p2, x2 + i)))
            return c1 - c2;
    }
    return 0;
}

static int string_indexof_char(QJSString *p, int c, int from)
{
    /* assuming 0 <= from <= p->len */
    int i, len = p->len;
    if (p->is_wide_char) {
        for (i = from; i < len; i++) {
            if (p->u.str16[i] == c)
                return i;
        }
    } else {
        if ((c & ~0xff) == 0) {
            for (i = from; i < len; i++) {
                if (p->u.str8[i] == (uint8_t)c)
                    return i;
            }
        }
    }
    return -1;
}

static int string_indexof(QJSString *p1, QJSString *p2, int from)
{
    /* assuming 0 <= from <= p1->len */
    int c, i, j, len1 = p1->len, len2 = p2->len;
    if (len2 == 0)
        return from;
    for (i = from, c = string_get(p2, 0); i + len2 <= len1; i = j + 1) {
        j = string_indexof_char(p1, c, i);
        if (j < 0 || j + len2 > len1)
            break;
        if (!string_cmp(p1, p2, j + 1, 1, len2 - 1))
            return j;
    }
    return -1;
}

static int64_t string_advance_index(QJSString *p, int64_t index, BOOL unicode)
{
    if (!unicode || index >= p->len || !p->is_wide_char) {
        index++;
    } else {
        int index32 = (int)index;
        string_getc(p, &index32);
        index = index32;
    }
    return index;
}

static QJSValue js_string_indexOf(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv, int lastIndexOf)
{
    QJSValue str, v;
    int i, len, v_len, pos, start, stop, ret, inc;
    QJSString *p;
    QJSString *p1;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    v = QJS_ToString(ctx, argv[0]);
    if (QJS_IsException(v))
        goto fail;
    p = QJS_VALUE_GET_STRING(str);
    p1 = QJS_VALUE_GET_STRING(v);
    len = p->len;
    v_len = p1->len;
    if (lastIndexOf) {
        pos = len - v_len;
        if (argc > 1) {
            double d;
            if (QJS_ToFloat64(ctx, &d, argv[1]))
                goto fail;
            if (!isnan(d)) {
                if (d <= 0)
                    pos = 0;
                else if (d < pos)
                    pos = d;
            }
        }
        start = pos;
        stop = 0;
        inc = -1;
    } else {
        pos = 0;
        if (argc > 1) {
            if (QJS_ToInt32Clamp(ctx, &pos, argv[1], 0, len, 0))
                goto fail;
        }
        start = pos;
        stop = len - v_len;
        inc = 1;
    }
    ret = -1;
    if (len >= v_len && inc * (stop - start) >= 0) {
        for (i = start;; i += inc) {
            if (!string_cmp(p, p1, i, 0, v_len)) {
                ret = i;
                break;
            }
            if (i == stop)
                break;
        }
    }
    QJS_FreeValue(ctx, str);
    QJS_FreeValue(ctx, v);
    return QJS_NewInt32(ctx, ret);

fail:
    QJS_FreeValue(ctx, str);
    QJS_FreeValue(ctx, v);
    return QJS_EXCEPTION;
}

/* return < 0 if exception or TRUE/FALSE */
static int js_is_regexp(QJSContext *ctx, QJSValueConst obj);

static QJSValue js_string_includes(QJSContext *ctx, QJSValueConst this_val,
                                  int argc, QJSValueConst *argv, int magic)
{
    QJSValue str, v = QJS_UNDEFINED;
    int i, len, v_len, pos, start, stop, ret;
    QJSString *p;
    QJSString *p1;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    ret = js_is_regexp(ctx, argv[0]);
    if (ret) {
        if (ret > 0)
            QJS_ThrowTypeError(ctx, "regex not supported");
        goto fail;
    }
    v = QJS_ToString(ctx, argv[0]);
    if (QJS_IsException(v))
        goto fail;
    p = QJS_VALUE_GET_STRING(str);
    p1 = QJS_VALUE_GET_STRING(v);
    len = p->len;
    v_len = p1->len;
    pos = (magic == 2) ? len : 0;
    if (argc > 1 && !QJS_IsUndefined(argv[1])) {
        if (QJS_ToInt32Clamp(ctx, &pos, argv[1], 0, len, 0))
            goto fail;
    }
    len -= v_len;
    ret = 0;
    if (magic == 0) {
        start = pos;
        stop = len;
    } else {
        if (magic == 1) {
            if (pos > len)
                goto done;
        } else {
            pos -= v_len;
        }
        start = stop = pos;
    }
    if (start >= 0 && start <= stop) {
        for (i = start;; i++) {
            if (!string_cmp(p, p1, i, 0, v_len)) {
                ret = 1;
                break;
            }
            if (i == stop)
                break;
        }
    }
 done:
    QJS_FreeValue(ctx, str);
    QJS_FreeValue(ctx, v);
    return QJS_NewBool(ctx, ret);

fail:
    QJS_FreeValue(ctx, str);
    QJS_FreeValue(ctx, v);
    return QJS_EXCEPTION;
}

static int check_regexp_g_flag(QJSContext *ctx, QJSValueConst regexp)
{
    int ret;
    QJSValue flags;

    ret = js_is_regexp(ctx, regexp);
    if (ret < 0)
        return -1;
    if (ret) {
        flags = QJS_GetProperty(ctx, regexp, QJS_ATOM_flags);
        if (QJS_IsException(flags))
            return -1;
        if (QJS_IsUndefined(flags) || QJS_IsNull(flags)) {
            QJS_ThrowTypeError(ctx, "cannot convert to object");
            return -1;
        }
        flags = QJS_ToStringFree(ctx, flags);
        if (QJS_IsException(flags))
            return -1;
        ret = string_indexof_char(QJS_VALUE_GET_STRING(flags), 'g', 0);
        QJS_FreeValue(ctx, flags);
        if (ret < 0) {
            QJS_ThrowTypeError(ctx, "regexp must have the 'g' flag");
            return -1;
        }
    }
    return 0;
}

static QJSValue js_string_match(QJSContext *ctx, QJSValueConst this_val,
                               int argc, QJSValueConst *argv, int atom)
{
    // match(rx), search(rx), matchAll(rx)
    // atom is QJS_ATOM_Symbol_match, QJS_ATOM_Symbol_search, or QJS_ATOM_Symbol_matchAll
    QJSValueConst O = this_val, regexp = argv[0], args[2];
    QJSValue matcher, S, rx, result, str;
    int args_len;

    if (QJS_IsUndefined(O) || QJS_IsNull(O))
        return QJS_ThrowTypeError(ctx, "cannot convert to object");

    if (!QJS_IsUndefined(regexp) && !QJS_IsNull(regexp)) {
        matcher = QJS_GetProperty(ctx, regexp, atom);
        if (QJS_IsException(matcher))
            return QJS_EXCEPTION;
        if (atom == QJS_ATOM_Symbol_matchAll) {
            if (check_regexp_g_flag(ctx, regexp) < 0) {
                QJS_FreeValue(ctx, matcher);
                return QJS_EXCEPTION;
            }
        }
        if (!QJS_IsUndefined(matcher) && !QJS_IsNull(matcher)) {
            return QJS_CallFree(ctx, matcher, regexp, 1, &O);
        }
    }
    S = QJS_ToString(ctx, O);
    if (QJS_IsException(S))
        return QJS_EXCEPTION;
    args_len = 1;
    args[0] = regexp;
    str = QJS_UNDEFINED;
    if (atom == QJS_ATOM_Symbol_matchAll) {
        str = QJS_NewString(ctx, "g");
        if (QJS_IsException(str))
            goto fail;
        args[args_len++] = (QJSValueConst)str;
    }
    rx = QJS_CallConstructor(ctx, ctx->regexp_ctor, args_len, args);
    QJS_FreeValue(ctx, str);
    if (QJS_IsException(rx)) {
    fail:
        QJS_FreeValue(ctx, S);
        return QJS_EXCEPTION;
    }
    result = QJS_InvokeFree(ctx, rx, atom, 1, (QJSValueConst *)&S);
    QJS_FreeValue(ctx, S);
    return result;
}

static QJSValue js_string___GetSubstitution(QJSContext *ctx, QJSValueConst this_val,
                                           int argc, QJSValueConst *argv)
{
    // GetSubstitution(matched, str, position, captures, namedCaptures, rep)
    QJSValueConst matched, str, captures, namedCaptures, rep;
    QJSValue capture, name, s;
    uint32_t position, len, matched_len, captures_len;
    int i, j, j0, k, k1;
    int c, c1;
    StringBuffer b_s, *b = &b_s;
    QJSString *sp, *rp;

    matched = argv[0];
    str = argv[1];
    captures = argv[3];
    namedCaptures = argv[4];
    rep = argv[5];

    if (!QJS_IsString(rep) || !QJS_IsString(str))
        return QJS_ThrowTypeError(ctx, "not a string");

    sp = QJS_VALUE_GET_STRING(str);
    rp = QJS_VALUE_GET_STRING(rep);

    string_buffer_init(ctx, b, 0);

    captures_len = 0;
    if (!QJS_IsUndefined(captures)) {
        if (js_get_length32(ctx, &captures_len, captures))
            goto exception;
    }
    if (js_get_length32(ctx, &matched_len, matched))
        goto exception;
    if (QJS_ToUint32(ctx, &position, argv[2]) < 0)
        goto exception;

    len = rp->len;
    i = 0;
    for(;;) {
        j = string_indexof_char(rp, '$', i);
        if (j < 0 || j + 1 >= len)
            break;
        string_buffer_concat(b, rp, i, j);
        j0 = j++;
        c = string_get(rp, j++);
        if (c == '$') {
            string_buffer_putc8(b, '$');
        } else if (c == '&') {
            if (string_buffer_concat_value(b, matched))
                goto exception;
        } else if (c == '`') {
            string_buffer_concat(b, sp, 0, position);
        } else if (c == '\'') {
            string_buffer_concat(b, sp, position + matched_len, sp->len);
        } else if (c >= '0' && c <= '9') {
            k = c - '0';
            if (j < len) {
                c1 = string_get(rp, j);
                if (c1 >= '0' && c1 <= '9') {
                    /* This behavior is specified in ES6 and refined in ECMA 2019 */
                    /* ECMA 2019 does not have the extra test, but
                       Test262 S15.5.4.11_A3_T1..3 require this behavior */
                    k1 = k * 10 + c1 - '0';
                    if (k1 >= 1 && k1 < captures_len) {
                        k = k1;
                        j++;
                    }
                }
            }
            if (k >= 1 && k < captures_len) {
                s = QJS_GetPropertyInt64(ctx, captures, k);
                if (QJS_IsException(s))
                    goto exception;
                if (!QJS_IsUndefined(s)) {
                    if (string_buffer_concat_value_free(b, s))
                        goto exception;
                }
            } else {
                goto norep;
            }
        } else if (c == '<' && !QJS_IsUndefined(namedCaptures)) {
            k = string_indexof_char(rp, '>', j);
            if (k < 0)
                goto norep;
            name = js_sub_string(ctx, rp, j, k);
            if (QJS_IsException(name))
                goto exception;
            capture = QJS_GetPropertyValue(ctx, namedCaptures, name);
            if (QJS_IsException(capture))
                goto exception;
            if (!QJS_IsUndefined(capture)) {
                if (string_buffer_concat_value_free(b, capture))
                    goto exception;
            }
            j = k + 1;
        } else {
        norep:
            string_buffer_concat(b, rp, j0, j);
        }
        i = j;
    }
    string_buffer_concat(b, rp, i, rp->len);
    return string_buffer_end(b);
exception:
    string_buffer_free(b);
    return QJS_EXCEPTION;
}

static QJSValue js_string_replace(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv,
                                 int is_replaceAll)
{
    // replace(rx, rep)
    QJSValueConst O = this_val, searchValue = argv[0], replaceValue = argv[1];
    QJSValueConst args[6];
    QJSValue str, search_str, replaceValue_str, repl_str;
    QJSString *sp, *searchp;
    StringBuffer b_s, *b = &b_s;
    int pos, functionalReplace, endOfLastMatch;
    BOOL is_first;

    if (QJS_IsUndefined(O) || QJS_IsNull(O))
        return QJS_ThrowTypeError(ctx, "cannot convert to object");

    search_str = QJS_UNDEFINED;
    replaceValue_str = QJS_UNDEFINED;
    repl_str = QJS_UNDEFINED;

    if (!QJS_IsUndefined(searchValue) && !QJS_IsNull(searchValue)) {
        QJSValue replacer;
        if (is_replaceAll) {
            if (check_regexp_g_flag(ctx, searchValue) < 0)
                return QJS_EXCEPTION;
        }
        replacer = QJS_GetProperty(ctx, searchValue, QJS_ATOM_Symbol_replace);
        if (QJS_IsException(replacer))
            return QJS_EXCEPTION;
        if (!QJS_IsUndefined(replacer) && !QJS_IsNull(replacer)) {
            args[0] = O;
            args[1] = replaceValue;
            return QJS_CallFree(ctx, replacer, searchValue, 2, args);
        }
    }
    string_buffer_init(ctx, b, 0);

    str = QJS_ToString(ctx, O);
    if (QJS_IsException(str))
        goto exception;
    search_str = QJS_ToString(ctx, searchValue);
    if (QJS_IsException(search_str))
        goto exception;
    functionalReplace = QJS_IsFunction(ctx, replaceValue);
    if (!functionalReplace) {
        replaceValue_str = QJS_ToString(ctx, replaceValue);
        if (QJS_IsException(replaceValue_str))
            goto exception;
    }

    sp = QJS_VALUE_GET_STRING(str);
    searchp = QJS_VALUE_GET_STRING(search_str);
    endOfLastMatch = 0;
    is_first = TRUE;
    for(;;) {
        if (unlikely(searchp->len == 0)) {
            if (is_first)
                pos = 0;
            else if (endOfLastMatch >= sp->len)
                pos = -1;
            else
                pos = endOfLastMatch + 1;
        } else {
            pos = string_indexof(sp, searchp, endOfLastMatch);
        }
        if (pos < 0) {
            if (is_first) {
                string_buffer_free(b);
                QJS_FreeValue(ctx, search_str);
                QJS_FreeValue(ctx, replaceValue_str);
                return str;
            } else {
                break;
            }
        }
        if (functionalReplace) {
            args[0] = search_str;
            args[1] = QJS_NewInt32(ctx, pos);
            args[2] = str;
            repl_str = QJS_ToStringFree(ctx, QJS_Call(ctx, replaceValue, QJS_UNDEFINED, 3, args));
        } else {
            args[0] = search_str;
            args[1] = str;
            args[2] = QJS_NewInt32(ctx, pos);
            args[3] = QJS_UNDEFINED;
            args[4] = QJS_UNDEFINED;
            args[5] = replaceValue_str;
            repl_str = js_string___GetSubstitution(ctx, QJS_UNDEFINED, 6, args);
        }
        if (QJS_IsException(repl_str))
            goto exception;

        string_buffer_concat(b, sp, endOfLastMatch, pos);
        string_buffer_concat_value_free(b, repl_str);
        endOfLastMatch = pos + searchp->len;
        is_first = FALSE;
        if (!is_replaceAll)
            break;
    }
    string_buffer_concat(b, sp, endOfLastMatch, sp->len);
    QJS_FreeValue(ctx, search_str);
    QJS_FreeValue(ctx, replaceValue_str);
    QJS_FreeValue(ctx, str);
    return string_buffer_end(b);

exception:
    string_buffer_free(b);
    QJS_FreeValue(ctx, search_str);
    QJS_FreeValue(ctx, replaceValue_str);
    QJS_FreeValue(ctx, str);
    return QJS_EXCEPTION;
}

static QJSValue js_string_split(QJSContext *ctx, QJSValueConst this_val,
                               int argc, QJSValueConst *argv)
{
    // split(sep, limit)
    QJSValueConst O = this_val, separator = argv[0], limit = argv[1];
    QJSValueConst args[2];
    QJSValue S, A, R, T;
    uint32_t lim, lengthA;
    int64_t p, q, s, r, e;
    QJSString *sp, *rp;

    if (QJS_IsUndefined(O) || QJS_IsNull(O))
        return QJS_ThrowTypeError(ctx, "cannot convert to object");

    S = QJS_UNDEFINED;
    A = QJS_UNDEFINED;
    R = QJS_UNDEFINED;

    if (!QJS_IsUndefined(separator) && !QJS_IsNull(separator)) {
        QJSValue splitter;
        splitter = QJS_GetProperty(ctx, separator, QJS_ATOM_Symbol_split);
        if (QJS_IsException(splitter))
            return QJS_EXCEPTION;
        if (!QJS_IsUndefined(splitter) && !QJS_IsNull(splitter)) {
            args[0] = O;
            args[1] = limit;
            return QJS_CallFree(ctx, splitter, separator, 2, args);
        }
    }
    S = QJS_ToString(ctx, O);
    if (QJS_IsException(S))
        goto exception;
    A = QJS_NewArray(ctx);
    if (QJS_IsException(A))
        goto exception;
    lengthA = 0;
    if (QJS_IsUndefined(limit)) {
        lim = 0xffffffff;
    } else {
        if (QJS_ToUint32(ctx, &lim, limit) < 0)
            goto exception;
    }
    sp = QJS_VALUE_GET_STRING(S);
    s = sp->len;
    R = QJS_ToString(ctx, separator);
    if (QJS_IsException(R))
        goto exception;
    rp = QJS_VALUE_GET_STRING(R);
    r = rp->len;
    p = 0;
    if (lim == 0)
        goto done;
    if (QJS_IsUndefined(separator))
        goto add_tail;
    if (s == 0) {
        if (r != 0)
            goto add_tail;
        goto done;
    }
    q = p;
    for (q = p; (q += !r) <= s - r - !r; q = p = e + r) {
        e = string_indexof(sp, rp, q);
        if (e < 0)
            break;
        T = js_sub_string(ctx, sp, p, e);
        if (QJS_IsException(T))
            goto exception;
        if (QJS_CreateDataPropertyUint32(ctx, A, lengthA++, T, 0) < 0)
            goto exception;
        if (lengthA == lim)
            goto done;
    }
add_tail:
    T = js_sub_string(ctx, sp, p, s);
    if (QJS_IsException(T))
        goto exception;
    if (QJS_CreateDataPropertyUint32(ctx, A, lengthA++, T,0 ) < 0)
        goto exception;
done:
    QJS_FreeValue(ctx, S);
    QJS_FreeValue(ctx, R);
    return A;

exception:
    QJS_FreeValue(ctx, A);
    QJS_FreeValue(ctx, S);
    QJS_FreeValue(ctx, R);
    return QJS_EXCEPTION;
}

static QJSValue js_string_substring(QJSContext *ctx, QJSValueConst this_val,
                                   int argc, QJSValueConst *argv)
{
    QJSValue str, ret;
    int a, b, start, end;
    QJSString *p;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    p = QJS_VALUE_GET_STRING(str);
    if (QJS_ToInt32Clamp(ctx, &a, argv[0], 0, p->len, 0)) {
        QJS_FreeValue(ctx, str);
        return QJS_EXCEPTION;
    }
    b = p->len;
    if (!QJS_IsUndefined(argv[1])) {
        if (QJS_ToInt32Clamp(ctx, &b, argv[1], 0, p->len, 0)) {
            QJS_FreeValue(ctx, str);
            return QJS_EXCEPTION;
        }
    }
    if (a < b) {
        start = a;
        end = b;
    } else {
        start = b;
        end = a;
    }
    ret = js_sub_string(ctx, p, start, end);
    QJS_FreeValue(ctx, str);
    return ret;
}

static QJSValue js_string_substr(QJSContext *ctx, QJSValueConst this_val,
                                int argc, QJSValueConst *argv)
{
    QJSValue str, ret;
    int a, len, n;
    QJSString *p;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    p = QJS_VALUE_GET_STRING(str);
    len = p->len;
    if (QJS_ToInt32Clamp(ctx, &a, argv[0], 0, len, len)) {
        QJS_FreeValue(ctx, str);
        return QJS_EXCEPTION;
    }
    n = len - a;
    if (!QJS_IsUndefined(argv[1])) {
        if (QJS_ToInt32Clamp(ctx, &n, argv[1], 0, len - a, 0)) {
            QJS_FreeValue(ctx, str);
            return QJS_EXCEPTION;
        }
    }
    ret = js_sub_string(ctx, p, a, a + n);
    QJS_FreeValue(ctx, str);
    return ret;
}

static QJSValue js_string_slice(QJSContext *ctx, QJSValueConst this_val,
                               int argc, QJSValueConst *argv)
{
    QJSValue str, ret;
    int len, start, end;
    QJSString *p;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    p = QJS_VALUE_GET_STRING(str);
    len = p->len;
    if (QJS_ToInt32Clamp(ctx, &start, argv[0], 0, len, len)) {
        QJS_FreeValue(ctx, str);
        return QJS_EXCEPTION;
    }
    end = len;
    if (!QJS_IsUndefined(argv[1])) {
        if (QJS_ToInt32Clamp(ctx, &end, argv[1], 0, len, len)) {
            QJS_FreeValue(ctx, str);
            return QJS_EXCEPTION;
        }
    }
    ret = js_sub_string(ctx, p, start, max_int(end, start));
    QJS_FreeValue(ctx, str);
    return ret;
}

static QJSValue js_string_pad(QJSContext *ctx, QJSValueConst this_val,
                             int argc, QJSValueConst *argv, int padEnd)
{
    QJSValue str, v = QJS_UNDEFINED;
    StringBuffer b_s, *b = &b_s;
    QJSString *p, *p1 = NULL;
    int n, len, c = ' ';

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        goto fail1;
    if (QJS_ToInt32Sat(ctx, &n, argv[0]))
        goto fail2;
    p = QJS_VALUE_GET_STRING(str);
    len = p->len;
    if (len >= n)
        return str;
    if (argc > 1 && !QJS_IsUndefined(argv[1])) {
        v = QJS_ToString(ctx, argv[1]);
        if (QJS_IsException(v))
            goto fail2;
        p1 = QJS_VALUE_GET_STRING(v);
        if (p1->len == 0) {
            QJS_FreeValue(ctx, v);
            return str;
        }
        if (p1->len == 1) {
            c = string_get(p1, 0);
            p1 = NULL;
        }
    }
    if (n > QJS_STRING_LEN_MAX) {
        QJS_ThrowInternalError(ctx, "string too long");
        goto fail2;
    }
    if (string_buffer_init(ctx, b, n))
        goto fail3;
    n -= len;
    if (padEnd) {
        if (string_buffer_concat(b, p, 0, len))
            goto fail;
    }
    if (p1) {
        while (n > 0) {
            int chunk = min_int(n, p1->len);
            if (string_buffer_concat(b, p1, 0, chunk))
                goto fail;
            n -= chunk;
        }
    } else {
        if (string_buffer_fill(b, c, n))
            goto fail;
    }
    if (!padEnd) {
        if (string_buffer_concat(b, p, 0, len))
            goto fail;
    }
    QJS_FreeValue(ctx, v);
    QJS_FreeValue(ctx, str);
    return string_buffer_end(b);

fail:
    string_buffer_free(b);
fail3:
    QJS_FreeValue(ctx, v);
fail2:
    QJS_FreeValue(ctx, str);
fail1:
    return QJS_EXCEPTION;
}

static QJSValue js_string_repeat(QJSContext *ctx, QJSValueConst this_val,
                                int argc, QJSValueConst *argv)
{
    QJSValue str;
    StringBuffer b_s, *b = &b_s;
    QJSString *p;
    int64_t val;
    int n, len;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        goto fail;
    if (QJS_ToInt64Sat(ctx, &val, argv[0]))
        goto fail;
    if (val < 0 || val > 2147483647) {
        QJS_ThrowRangeError(ctx, "invalid repeat count");
        goto fail;
    }
    n = val;
    p = QJS_VALUE_GET_STRING(str);
    len = p->len;
    if (len == 0 || n == 1)
        return str;
    if (val * len > QJS_STRING_LEN_MAX) {
        QJS_ThrowInternalError(ctx, "string too long");
        goto fail;
    }
    if (string_buffer_init2(ctx, b, n * len, p->is_wide_char))
        goto fail;
    if (len == 1) {
        string_buffer_fill(b, string_get(p, 0), n);
    } else {
        while (n-- > 0) {
            string_buffer_concat(b, p, 0, len);
        }
    }
    QJS_FreeValue(ctx, str);
    return string_buffer_end(b);

fail:
    QJS_FreeValue(ctx, str);
    return QJS_EXCEPTION;
}

static QJSValue js_string_trim(QJSContext *ctx, QJSValueConst this_val,
                              int argc, QJSValueConst *argv, int magic)
{
    QJSValue str, ret;
    int a, b, len;
    QJSString *p;

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return str;
    p = QJS_VALUE_GET_STRING(str);
    a = 0;
    b = len = p->len;
    if (magic & 1) {
        while (a < len && lre_is_space(string_get(p, a)))
            a++;
    }
    if (magic & 2) {
        while (b > a && lre_is_space(string_get(p, b - 1)))
            b--;
    }
    ret = js_sub_string(ctx, p, a, b);
    QJS_FreeValue(ctx, str);
    return ret;
}

static QJSValue js_string___quote(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv)
{
    return QJS_ToQuotedString(ctx, this_val);
}

/* return 0 if before the first char */
static int string_prevc(QJSString *p, int *pidx)
{
    int idx, c, c1;

    idx = *pidx;
    if (idx <= 0)
        return 0;
    idx--;
    if (p->is_wide_char) {
        c = p->u.str16[idx];
        if (c >= 0xdc00 && c < 0xe000 && idx > 0) {
            c1 = p->u.str16[idx - 1];
            if (c1 >= 0xd800 && c1 <= 0xdc00) {
                c = (((c1 & 0x3ff) << 10) | (c & 0x3ff)) + 0x10000;
                idx--;
            }
        }
    } else {
        c = p->u.str8[idx];
    }
    *pidx = idx;
    return c;
}

static BOOL test_final_sigma(QJSString *p, int sigma_pos)
{
    int k, c1;

    /* before C: skip case ignorable chars and check there is
       a cased letter */
    k = sigma_pos;
    for(;;) {
        c1 = string_prevc(p, &k);
        if (!lre_is_case_ignorable(c1))
            break;
    }
    if (!lre_is_cased(c1))
        return FALSE;

    /* after C: skip case ignorable chars and check there is
       no cased letter */
    k = sigma_pos + 1;
    for(;;) {
        if (k >= p->len)
            return TRUE;
        c1 = string_getc(p, &k);
        if (!lre_is_case_ignorable(c1))
            break;
    }
    return !lre_is_cased(c1);
}

static QJSValue js_string_localeCompare(QJSContext *ctx, QJSValueConst this_val,
                                       int argc, QJSValueConst *argv)
{
    QJSValue a, b;
    int cmp;

    a = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(a))
        return QJS_EXCEPTION;
    b = QJS_ToString(ctx, argv[0]);
    if (QJS_IsException(b)) {
        QJS_FreeValue(ctx, a);
        return QJS_EXCEPTION;
    }
    cmp = js_string_compare(ctx, QJS_VALUE_GET_STRING(a), QJS_VALUE_GET_STRING(b));
    QJS_FreeValue(ctx, a);
    QJS_FreeValue(ctx, b);
    return QJS_NewInt32(ctx, cmp);
}

static QJSValue js_string_toLowerCase(QJSContext *ctx, QJSValueConst this_val,
                                     int argc, QJSValueConst *argv, int to_lower)
{
    QJSValue val;
    StringBuffer b_s, *b = &b_s;
    QJSString *p;
    int i, c, j, l;
    uint32_t res[LRE_CC_RES_LEN_MAX];

    val = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    p = QJS_VALUE_GET_STRING(val);
    if (p->len == 0)
        return val;
    if (string_buffer_init(ctx, b, p->len))
        goto fail;
    for(i = 0; i < p->len;) {
        c = string_getc(p, &i);
        if (c == 0x3a3 && to_lower && test_final_sigma(p, i - 1)) {
            res[0] = 0x3c2; /* final sigma */
            l = 1;
        } else {
            l = lre_case_conv(res, c, to_lower);
        }
        for(j = 0; j < l; j++) {
            if (string_buffer_putc(b, res[j]))
                goto fail;
        }
    }
    QJS_FreeValue(ctx, val);
    return string_buffer_end(b);
 fail:
    QJS_FreeValue(ctx, val);
    string_buffer_free(b);
    return QJS_EXCEPTION;
}

#ifdef CONFIG_ALL_UNICODE

/* return (-1, NULL) if exception, otherwise (len, buf) */
static int QJS_ToUTF32String(QJSContext *ctx, uint32_t **pbuf, QJSValueConst val1)
{
    QJSValue val;
    QJSString *p;
    uint32_t *buf;
    int i, j, len;

    val = QJS_ToString(ctx, val1);
    if (QJS_IsException(val))
        return -1;
    p = QJS_VALUE_GET_STRING(val);
    len = p->len;
    /* UTF32 buffer length is len minus the number of correct surrogates pairs */
    buf = js_malloc(ctx, sizeof(buf[0]) * max_int(len, 1));
    if (!buf) {
        QJS_FreeValue(ctx, val);
        goto fail;
    }
    for(i = j = 0; i < len;)
        buf[j++] = string_getc(p, &i);
    QJS_FreeValue(ctx, val);
    *pbuf = buf;
    return j;
 fail:
    *pbuf = NULL;
    return -1;
}

static QJSValue QJS_NewUTF32String(QJSContext *ctx, const uint32_t *buf, int len)
{
    int i;
    StringBuffer b_s, *b = &b_s;
    if (string_buffer_init(ctx, b, len))
        return QJS_EXCEPTION;
    for(i = 0; i < len; i++) {
        if (string_buffer_putc(b, buf[i]))
            goto fail;
    }
    return string_buffer_end(b);
 fail:
    string_buffer_free(b);
    return QJS_EXCEPTION;
}

static QJSValue js_string_normalize(QJSContext *ctx, QJSValueConst this_val,
                                   int argc, QJSValueConst *argv)
{
    const char *form, *p;
    size_t form_len;
    int is_compat, buf_len, out_len;
    UnicodeNormalizationEnum n_type;
    QJSValue val;
    uint32_t *buf, *out_buf;

    val = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(val))
        return val;
    buf_len = QJS_ToUTF32String(ctx, &buf, val);
    QJS_FreeValue(ctx, val);
    if (buf_len < 0)
        return QJS_EXCEPTION;

    if (argc == 0 || QJS_IsUndefined(argv[0])) {
        n_type = UNICODE_NFC;
    } else {
        form = QJS_ToCStringLen(ctx, &form_len, argv[0]);
        if (!form)
            goto fail1;
        p = form;
        if (p[0] != 'N' || p[1] != 'F')
            goto bad_form;
        p += 2;
        is_compat = FALSE;
        if (*p == 'K') {
            is_compat = TRUE;
            p++;
        }
        if (*p == 'C' || *p == 'D') {
            n_type = UNICODE_NFC + is_compat * 2 + (*p - 'C');
            if ((p + 1 - form) != form_len)
                goto bad_form;
        } else {
        bad_form:
            QJS_FreeCString(ctx, form);
            QJS_ThrowRangeError(ctx, "bad normalization form");
        fail1:
            js_free(ctx, buf);
            return QJS_EXCEPTION;
        }
        QJS_FreeCString(ctx, form);
    }

    out_len = unicode_normalize(&out_buf, buf, buf_len, n_type,
                                ctx->rt, (DynBufReallocFunc *)js_realloc_rt);
    js_free(ctx, buf);
    if (out_len < 0)
        return QJS_EXCEPTION;
    val = QJS_NewUTF32String(ctx, out_buf, out_len);
    js_free(ctx, out_buf);
    return val;
}
#endif /* CONFIG_ALL_UNICODE */

