/* String Iterator */

static QJSValue js_string_iterator_next(QJSContext *ctx, QJSValueConst this_val,
                                       int argc, QJSValueConst *argv,
                                       BOOL *pdone, int magic)
{
    QJSArrayIteratorData *it;
    uint32_t idx, c, start;
    QJSString *p;

    it = QJS_GetOpaque2(ctx, this_val, QJS_CLASS_STRING_ITERATOR);
    if (!it) {
        *pdone = FALSE;
        return QJS_EXCEPTION;
    }
    if (QJS_IsUndefined(it->obj))
        goto done;
    p = QJS_VALUE_GET_STRING(it->obj);
    idx = it->idx;
    if (idx >= p->len) {
        QJS_FreeValue(ctx, it->obj);
        it->obj = QJS_UNDEFINED;
    done:
        *pdone = TRUE;
        return QJS_UNDEFINED;
    }

    start = idx;
    c = string_getc(p, (int *)&idx);
    it->idx = idx;
    *pdone = FALSE;
    if (c <= 0xffff) {
        return js_new_string_char(ctx, c);
    } else {
        return js_new_string16(ctx, p->u.str16 + start, 2);
    }
}

/* ES6 Annex B 2.3.2 etc. */
enum {
    magic_string_anchor,
    magic_string_big,
    magic_string_blink,
    magic_string_bold,
    magic_string_fixed,
    magic_string_fontcolor,
    magic_string_fontsize,
    magic_string_italics,
    magic_string_link,
    magic_string_small,
    magic_string_strike,
    magic_string_sub,
    magic_string_sup,
};

static QJSValue js_string_CreateHTML(QJSContext *ctx, QJSValueConst this_val,
                                    int argc, QJSValueConst *argv, int magic)
{
    QJSValue str;
    const QJSString *p;
    StringBuffer b_s, *b = &b_s;
    static struct { const char *tag, *attr; } const defs[] = {
        { "a", "name" }, { "big", NULL }, { "blink", NULL }, { "b", NULL },
        { "tt", NULL }, { "font", "color" }, { "font", "size" }, { "i", NULL },
        { "a", "href" }, { "small", NULL }, { "strike", NULL },
        { "sub", NULL }, { "sup", NULL },
    };

    str = QJS_ToStringCheckObject(ctx, this_val);
    if (QJS_IsException(str))
        return QJS_EXCEPTION;
    string_buffer_init(ctx, b, 7);
    string_buffer_putc8(b, '<');
    string_buffer_puts8(b, defs[magic].tag);
    if (defs[magic].attr) {
        // r += " " + attr + "=\"" + value + "\"";
        QJSValue value;
        int i;

        string_buffer_putc8(b, ' ');
        string_buffer_puts8(b, defs[magic].attr);
        string_buffer_puts8(b, "=\"");
        value = QJS_ToStringCheckObject(ctx, argv[0]);
        if (QJS_IsException(value)) {
            QJS_FreeValue(ctx, str);
            string_buffer_free(b);
            return QJS_EXCEPTION;
        }
        p = QJS_VALUE_GET_STRING(value);
        for (i = 0; i < p->len; i++) {
            int c = string_get(p, i);
            if (c == '"') {
                string_buffer_puts8(b, "&quot;");
            } else {
                string_buffer_putc16(b, c);
            }
        }
        QJS_FreeValue(ctx, value);
        string_buffer_putc8(b, '\"');
    }
    // return r + ">" + str + "</" + tag + ">";
    string_buffer_putc8(b, '>');
    string_buffer_concat_value_free(b, str);
    string_buffer_puts8(b, "</");
    string_buffer_puts8(b, defs[magic].tag);
    string_buffer_putc8(b, '>');
    return string_buffer_end(b);
}

