/* Date */

#if 0
/* OS dependent: return the UTC time in ms since 1970. */
static QJSValue js___date_now(QJSContext *ctx, QJSValueConst this_val,
                             int argc, QJSValueConst *argv)
{
    int64_t d;
    struct timeval tv;
    gettimeofday(&tv, NULL);
    d = (int64_t)tv.tv_sec * 1000 + (tv.tv_usec / 1000);
    return QJS_NewInt64(ctx, d);
}
#endif

/* OS dependent: return the UTC time in microseconds since 1970. */
static QJSValue js___date_clock(QJSContext *ctx, QJSValueConst this_val,
                               int argc, QJSValueConst *argv)
{
    int64_t d;
#ifndef _WIN32
    struct timeval tv;
    gettimeofday(&tv, NULL);
    d = (int64_t)tv.tv_sec * 1000000 + tv.tv_usec;
#else
    // in 100-nanosecond intervals.
    const uint64_t time_between_1601_and_unix_epoch = (uint64_t)116444736000000000ull;
    SYSTEMTIME st;
    FILETIME ft;
    GetSystemTime(&st);
    SystemTimeToFileTime(&st, &ft);
    d = (uint64_t)ft.dwLowDateTime;
    d += (uint64_t)ft.dwHighDateTime << 32;
    // at this point we have tte number of 100-nanoseconds intervals since Jan
    // 1, 1601 (UTC).
    d -= time_between_1601_and_unix_epoch;
    d /= 10ull;
#endif
    return QJS_NewInt64(ctx, d);
}

/* OS dependent. d = argv[0] is in ms from 1970. Return the difference
   between UTC time and local time 'd' in minutes */
static int getTimezoneOffset(int64_t time) {
#if defined(_WIN32)
    /* XXX: TODO */
    return 0;
#else
    time_t ti;
    struct tm tm;

    time /= 1000; /* convert to seconds */
    if (sizeof(time_t) == 4) {
        /* on 32-bit systems, we need to clamp the time value to the
           range of `time_t`. This is better than truncating values to
           32 bits and hopefully provides the same result as 64-bit
           implementation of localtime_r.
         */
        if ((time_t)-1 < 0) {
            if (time < INT32_MIN) {
                time = INT32_MIN;
            } else if (time > INT32_MAX) {
                time = INT32_MAX;
            }
        } else {
            if (time < 0) {
                time = 0;
            } else if (time > UINT32_MAX) {
                time = UINT32_MAX;
            }
        }
    }
    ti = time;
    localtime_r(&ti, &tm);
    return -tm.tm_gmtoff / 60;
#endif
}

#if 0
static QJSValue js___date_getTimezoneOffset(QJSContext *ctx, QJSValueConst this_val,
                                           int argc, QJSValueConst *argv)
{
    double dd;

    if (QJS_ToFloat64(ctx, &dd, argv[0]))
        return QJS_EXCEPTION;
    if (isnan(dd))
        return __JS_NewFloat64(ctx, dd);
    else
        return QJS_NewInt32(ctx, getTimezoneOffset((int64_t)dd));
}

static QJSValue js_get_prototype_from_ctor(QJSContext *ctx, QJSValueConst ctor,
                                          QJSValueConst def_proto)
{
    QJSValue proto;
    proto = QJS_GetProperty(ctx, ctor, QJS_ATOM_prototype);
    if (QJS_IsException(proto))
        return proto;
    if (!QJS_IsObject(proto)) {
        QJS_FreeValue(ctx, proto);
        proto = QJS_DupValue(ctx, def_proto);
    }
    return proto;
}

/* create a new date object */
static QJSValue js___date_create(QJSContext *ctx, QJSValueConst this_val,
                                int argc, QJSValueConst *argv)
{
    QJSValue obj, proto;
    proto = js_get_prototype_from_ctor(ctx, argv[0], argv[1]);
    if (QJS_IsException(proto))
        return proto;
    obj = QJS_NewObjectProtoClass(ctx, proto, QJS_CLASS_DATE);
    QJS_FreeValue(ctx, proto);
    if (!QJS_IsException(obj))
        QJS_SetObjectData(ctx, obj, QJS_DupValue(ctx, argv[2]));
    return obj;
}
#endif

/* RegExp */

static void js_regexp_finalizer(QJSRuntime *rt, QJSValue val)
{
    QJSObject *p = QJS_VALUE_GET_OBJ(val);
    QJSRegExp *re = &p->u.regexp;
    QJS_FreeValueRT(rt, QJS_MKPTR(QJS_TAG_STRING, re->bytecode));
    QJS_FreeValueRT(rt, QJS_MKPTR(QJS_TAG_STRING, re->pattern));
}

/* create a string containing the RegExp bytecode */
static QJSValue js_compile_regexp(QJSContext *ctx, QJSValueConst pattern,
                                 QJSValueConst flags)
{
    const char *str;
    int re_flags, mask;
    uint8_t *re_bytecode_buf;
    size_t i, len;
    int re_bytecode_len;
    QJSValue ret;
    char error_msg[64];

    re_flags = 0;
    if (!QJS_IsUndefined(flags)) {
        str = QJS_ToCStringLen(ctx, &len, flags);
        if (!str)
            return QJS_EXCEPTION;
        /* XXX: re_flags = LRE_FLAG_OCTAL unless strict mode? */
        for (i = 0; i < len; i++) {
            switch(str[i]) {
            case 'g':
                mask = LRE_FLAG_GLOBAL;
                break;
            case 'i':
                mask = LRE_FLAG_IGNORECASE;
                break;
            case 'm':
                mask = LRE_FLAG_MULTILINE;
                break;
            case 's':
                mask = LRE_FLAG_DOTALL;
                break;
            case 'u':
                mask = LRE_FLAG_UTF16;
                break;
            case 'y':
                mask = LRE_FLAG_STICKY;
                break;
            default:
                goto bad_flags;
            }
            if ((re_flags & mask) != 0) {
            bad_flags:
                QJS_FreeCString(ctx, str);
                return QJS_ThrowSyntaxError(ctx, "invalid regular expression flags");
            }
            re_flags |= mask;
        }
        QJS_FreeCString(ctx, str);
    }

    str = QJS_ToCStringLen2(ctx, &len, pattern, !(re_flags & LRE_FLAG_UTF16));
    if (!str)
        return QJS_EXCEPTION;
    re_bytecode_buf = lre_compile(&re_bytecode_len, error_msg,
                                  sizeof(error_msg), str, len, re_flags, ctx);
    QJS_FreeCString(ctx, str);
    if (!re_bytecode_buf) {
        QJS_ThrowSyntaxError(ctx, "%s", error_msg);
        return QJS_EXCEPTION;
    }

    ret = js_new_string8(ctx, re_bytecode_buf, re_bytecode_len);
    js_free(ctx, re_bytecode_buf);
    return ret;
}

/* create a RegExp object from a string containing the RegExp bytecode
   and the source pattern */
static QJSValue js_regexp_constructor_internal(QJSContext *ctx, QJSValueConst ctor,
                                              QJSValue pattern, QJSValue bc)
{
    QJSValue obj;
    QJSObject *p;
    QJSRegExp *re;

    /* sanity check */
    if (QJS_VALUE_GET_TAG(bc) != QJS_TAG_STRING ||
        QJS_VALUE_GET_TAG(pattern) != QJS_TAG_STRING) {
        QJS_ThrowTypeError(ctx, "string expected");
    fail:
        QJS_FreeValue(ctx, bc);
        QJS_FreeValue(ctx, pattern);
        return QJS_EXCEPTION;
    }

    obj = js_create_from_ctor(ctx, ctor, QJS_CLASS_REGEXP);
    if (QJS_IsException(obj))
        goto fail;
    p = QJS_VALUE_GET_OBJ(obj);
    re = &p->u.regexp;
    re->pattern = QJS_VALUE_GET_STRING(pattern);
    re->bytecode = QJS_VALUE_GET_STRING(bc);
    QJS_DefinePropertyValue(ctx, obj, QJS_ATOM_lastIndex, QJS_NewInt32(ctx, 0),
                           QJS_PROP_WRITABLE);
    return obj;
}

static QJSRegExp *js_get_regexp(QJSContext *ctx, QJSValueConst obj, BOOL throw_error)
{
    if (QJS_VALUE_GET_TAG(obj) == QJS_TAG_OBJECT) {
        QJSObject *p = QJS_VALUE_GET_OBJ(obj);
        if (p->class_id == QJS_CLASS_REGEXP)
            return &p->u.regexp;
    }
    if (throw_error) {
        QJS_ThrowTypeErrorInvalidClass(ctx, QJS_CLASS_REGEXP);
    }
    return NULL;
}

/* return < 0 if exception or TRUE/FALSE */
static int js_is_regexp(QJSContext *ctx, QJSValueConst obj)
{
    QJSValue m;

    if (!QJS_IsObject(obj))
        return FALSE;
    m = QJS_GetProperty(ctx, obj, QJS_ATOM_Symbol_match);
    if (QJS_IsException(m))
        return -1;
    if (!QJS_IsUndefined(m))
        return QJS_ToBoolFree(ctx, m);
    return js_get_regexp(ctx, obj, FALSE) != NULL;
}

static QJSValue js_regexp_constructor(QJSContext *ctx, QJSValueConst new_target,
                                     int argc, QJSValueConst *argv)
{
    QJSValue pattern, flags, bc, val;
    QJSValueConst pat, flags1;
    QJSRegExp *re;
    int pat_is_regexp;

    pat = argv[0];
    flags1 = argv[1];
    pat_is_regexp = js_is_regexp(ctx, pat);
    if (pat_is_regexp < 0)
        return QJS_EXCEPTION;
    if (QJS_IsUndefined(new_target)) {
        /* called as a function */
        new_target = QJS_GetActiveFunction(ctx);
        if (pat_is_regexp && QJS_IsUndefined(flags1)) {
            QJSValue ctor;
            BOOL res;
            ctor = QJS_GetProperty(ctx, pat, QJS_ATOM_constructor);
            if (QJS_IsException(ctor))
                return ctor;
            res = js_same_value(ctx, ctor, new_target);
            QJS_FreeValue(ctx, ctor);
            if (res)
                return QJS_DupValue(ctx, pat);
        }
    }
    re = js_get_regexp(ctx, pat, FALSE);
    if (re) {
        pattern = QJS_DupValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re->pattern));
        if (QJS_IsUndefined(flags1)) {
            bc = QJS_DupValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re->bytecode));
            goto no_compilation;
        } else {
            flags = QJS_ToString(ctx, flags1);
            if (QJS_IsException(flags))
                goto fail;
        }
    } else {
        flags = QJS_UNDEFINED;
        if (pat_is_regexp) {
            pattern = QJS_GetProperty(ctx, pat, QJS_ATOM_source);
            if (QJS_IsException(pattern))
                goto fail;
            if (QJS_IsUndefined(flags1)) {
                flags = QJS_GetProperty(ctx, pat, QJS_ATOM_flags);
                if (QJS_IsException(flags))
                    goto fail;
            } else {
                flags = QJS_DupValue(ctx, flags1);
            }
        } else {
            pattern = QJS_DupValue(ctx, pat);
            flags = QJS_DupValue(ctx, flags1);
        }
        if (QJS_IsUndefined(pattern)) {
            pattern = QJS_AtomToString(ctx, QJS_ATOM_empty_string);
        } else {
            val = pattern;
            pattern = QJS_ToString(ctx, val);
            QJS_FreeValue(ctx, val);
            if (QJS_IsException(pattern))
                goto fail;
        }
    }
    bc = js_compile_regexp(ctx, pattern, flags);
    if (QJS_IsException(bc))
        goto fail;
    QJS_FreeValue(ctx, flags);
 no_compilation:
    return js_regexp_constructor_internal(ctx, new_target, pattern, bc);
 fail:
    QJS_FreeValue(ctx, pattern);
    QJS_FreeValue(ctx, flags);
    return QJS_EXCEPTION;
}

static QJSValue js_regexp_compile(QJSContext *ctx, QJSValueConst this_val,
                                 int argc, QJSValueConst *argv)
{
    QJSRegExp *re1, *re;
    QJSValueConst pattern1, flags1;
    QJSValue bc, pattern;

    re = js_get_regexp(ctx, this_val, TRUE);
    if (!re)
        return QJS_EXCEPTION;
    pattern1 = argv[0];
    flags1 = argv[1];
    re1 = js_get_regexp(ctx, pattern1, FALSE);
    if (re1) {
        if (!QJS_IsUndefined(flags1))
            return QJS_ThrowTypeError(ctx, "flags must be undefined");
        pattern = QJS_DupValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re1->pattern));
        bc = QJS_DupValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re1->bytecode));
    } else {
        bc = QJS_UNDEFINED;
        if (QJS_IsUndefined(pattern1))
            pattern = QJS_AtomToString(ctx, QJS_ATOM_empty_string);
        else
            pattern = QJS_ToString(ctx, pattern1);
        if (QJS_IsException(pattern))
            goto fail;
        bc = js_compile_regexp(ctx, pattern, flags1);
        if (QJS_IsException(bc))
            goto fail;
    }
    QJS_FreeValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re->pattern));
    QJS_FreeValue(ctx, QJS_MKPTR(QJS_TAG_STRING, re->bytecode));
    re->pattern = QJS_VALUE_GET_STRING(pattern);
    re->bytecode = QJS_VALUE_GET_STRING(bc);
    if (QJS_SetProperty(ctx, this_val, QJS_ATOM_lastIndex,
                       QJS_NewInt32(ctx, 0)) < 0)
        return QJS_EXCEPTION;
    return QJS_DupValue(ctx, this_val);
 fail:
    QJS_FreeValue(ctx, pattern);
    QJS_FreeValue(ctx, bc);
    return QJS_EXCEPTION;
}

