static QJSValue js_regexp_get_source(QJSContext *ctx, QJSValueConst this_val)
{
    QJSRegExp *re;
    QJSString *p;
    StringBuffer b_s, *b = &b_s;
    int i, n, c, c2, bra;

    if (QJS_VALUE_GET_TAG(this_val) != QJS_TAG_OBJECT)
        return QJS_ThrowTypeErrorNotAnObject(ctx);

    if (js_same_value(ctx, this_val, ctx->class_proto[QJS_CLASS_REGEXP]))
        goto empty_regex;

    re = js_get_regexp(ctx, this_val, TRUE);
    if (!re)
        return QJS_EXCEPTION;

    p = re->pattern;

    if (p->len == 0) {
    empty_regex:
        return QJS_NewString(ctx, "(?:)");
    }
    string_buffer_init2(ctx, b, p->len, p->is_wide_char);

    /* Escape '/' and newline sequences as needed */
    bra = 0;
    for (i = 0, n = p->len; i < n;) {
        c2 = -1;
        switch (c = string_get(p, i++)) {
        case '\\':
            if (i < n)
                c2 = string_get(p, i++);
            break;
        case ']':
            bra = 0;
            break;
        case '[':
            if (!bra) {
                if (i < n && string_get(p, i) == ']')
                    c2 = string_get(p, i++);
                bra = 1;
            }
            break;
        case '\n':
            c = '\\';
            c2 = 'n';
            break;
        case '\r':
            c = '\\';
            c2 = 'r';
            break;
        case '/':
            if (!bra) {
                c = '\\';
                c2 = '/';
            }
            break;
        }
        string_buffer_putc16(b, c);
        if (c2 >= 0)
            string_buffer_putc16(b, c2);
    }
    return string_buffer_end(b);
}

static QJSValue js_regexp_get_flag(QJSContext *ctx, QJSValueConst this_val, int mask)
{
    QJSRegExp *re;
    int flags;

    if (QJS_VALUE_GET_TAG(this_val) != QJS_TAG_OBJECT)
        return QJS_ThrowTypeErrorNotAnObject(ctx);

    re = js_get_regexp(ctx, this_val, FALSE);
    if (!re) {
        if (js_same_value(ctx, this_val, ctx->class_proto[QJS_CLASS_REGEXP]))
            return QJS_UNDEFINED;
        else
            return QJS_ThrowTypeErrorInvalidClass(ctx, QJS_CLASS_REGEXP);
    }

    flags = lre_get_flags(re->bytecode->u.str8);
    return QJS_NewBool(ctx, (flags & mask) != 0);
}

static QJSValue js_regexp_get_flags(QJSContext *ctx, QJSValueConst this_val)
{
    char str[8], *p = str;
    int res;

    if (QJS_VALUE_GET_TAG(this_val) != QJS_TAG_OBJECT)
        return QJS_ThrowTypeErrorNotAnObject(ctx);

    res = QJS_ToBoolFree(ctx, QJS_GetProperty(ctx, this_val, QJS_ATOM_global));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 'g';
    res = QJS_ToBoolFree(ctx, QJS_GetPropertyStr(ctx, this_val, "ignoreCase"));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 'i';
    res = QJS_ToBoolFree(ctx, QJS_GetPropertyStr(ctx, this_val, "multiline"));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 'm';
    res = QJS_ToBoolFree(ctx, QJS_GetPropertyStr(ctx, this_val, "dotAll"));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 's';
    res = QJS_ToBoolFree(ctx, QJS_GetProperty(ctx, this_val, QJS_ATOM_unicode));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 'u';
    res = QJS_ToBoolFree(ctx, QJS_GetPropertyStr(ctx, this_val, "sticky"));
    if (res < 0)
        goto exception;
    if (res)
        *p++ = 'y';
    return QJS_NewStringLen(ctx, str, p - str);

exception:
    return QJS_EXCEPTION;
}

static QJSValue js_regexp_toString(QJSContext *ctx, QJSValueConst this_val,
                                  int argc, QJSValueConst *argv)
{
    QJSValue pattern, flags;
    StringBuffer b_s, *b = &b_s;

    if (!QJS_IsObject(this_val))
        return QJS_ThrowTypeErrorNotAnObject(ctx);

    string_buffer_init(ctx, b, 0);
    string_buffer_putc8(b, '/');
    pattern = QJS_GetProperty(ctx, this_val, QJS_ATOM_source);
    if (string_buffer_concat_value_free(b, pattern))
        goto fail;
    string_buffer_putc8(b, '/');
    flags = QJS_GetProperty(ctx, this_val, QJS_ATOM_flags);
    if (string_buffer_concat_value_free(b, flags))
        goto fail;
    return string_buffer_end(b);

fail:
    string_buffer_free(b);
    return QJS_EXCEPTION;
}

BOOL lre_check_stack_overflow(void *opaque, size_t alloca_size)
{
    QJSContext *ctx = opaque;
    return js_check_stack_overflow(ctx->rt, alloca_size);
}

void *lre_realloc(void *opaque, void *ptr, size_t size)
{
    QJSContext *ctx = opaque;
    /* No QJS exception is raised here */
    return js_realloc_rt(ctx->rt, ptr, size);
}

static QJSValue js_regexp_exec(QJSContext *ctx, QJSValueConst this_val,
                              int argc, QJSValueConst *argv)
{
    QJSRegExp *re = js_get_regexp(ctx, this_val, TRUE);
    QJSString *str;
    QJSValue str_val, obj, val, groups = QJS_UNDEFINED;
    uint8_t *re_bytecode;
    int ret;
    uint8_t **capture, *str_buf;
    int capture_count, shift, i, re_flags;
    int64_t last_index;
    const char *group_name_ptr;

    if (!re)
        return QJS_EXCEPTION;
    str_val = QJS_ToString(ctx, argv[0]);
    if (QJS_IsException(str_val))
        return str_val;
    val = QJS_GetProperty(ctx, this_val, QJS_ATOM_lastIndex);
    if (QJS_IsException(val) ||
        QJS_ToLengthFree(ctx, &last_index, val)) {
        QJS_FreeValue(ctx, str_val);
        return QJS_EXCEPTION;
    }
    re_bytecode = re->bytecode->u.str8;
    re_flags = lre_get_flags(re_bytecode);
    if ((re_flags & (LRE_FLAG_GLOBAL | LRE_FLAG_STICKY)) == 0) {
        last_index = 0;
    }
    str = QJS_VALUE_GET_STRING(str_val);
    capture_count = lre_get_capture_count(re_bytecode);
    capture = NULL;
    if (capture_count > 0) {
        capture = js_malloc(ctx, sizeof(capture[0]) * capture_count * 2);
        if (!capture) {
            QJS_FreeValue(ctx, str_val);
            return QJS_EXCEPTION;
        }
    }
    shift = str->is_wide_char;
    str_buf = str->u.str8;
    if (last_index > str->len) {
        ret = 2;
    } else {
        ret = lre_exec(capture, re_bytecode,
                       str_buf, last_index, str->len,
                       shift, ctx);
    }
    obj = QJS_NULL;
    if (ret != 1) {
        if (ret >= 0) {
            if (ret == 2 || (re_flags & (LRE_FLAG_GLOBAL | LRE_FLAG_STICKY))) {
                if (QJS_SetProperty(ctx, this_val, QJS_ATOM_lastIndex,
                                   QJS_NewInt32(ctx, 0)) < 0)
                    goto fail;
            }
        } else {
            QJS_ThrowInternalError(ctx, "out of memory in regexp execution");
            goto fail;
        }
        QJS_FreeValue(ctx, str_val);
    } else {
        int prop_flags;
        if (re_flags & (LRE_FLAG_GLOBAL | LRE_FLAG_STICKY)) {
            if (QJS_SetProperty(ctx, this_val, QJS_ATOM_lastIndex,
                               QJS_NewInt32(ctx, (capture[1] - str_buf) >> shift)) < 0)
                goto fail;
        }
        obj = QJS_NewArray(ctx);
        if (QJS_IsException(obj))
            goto fail;
        prop_flags = QJS_PROP_C_W_E | QJS_PROP_THROW;
        group_name_ptr = lre_get_groupnames(re_bytecode);
        if (group_name_ptr) {
            groups = QJS_NewObjectProto(ctx, QJS_NULL);
            if (QJS_IsException(groups))
                goto fail;
        }

        for(i = 0; i < capture_count; i++) {
            int start, end;
            QJSValue val;
            if (capture[2 * i] == NULL ||
                capture[2 * i + 1] == NULL) {
                val = QJS_UNDEFINED;
            } else {
                start = (capture[2 * i] - str_buf) >> shift;
                end = (capture[2 * i + 1] - str_buf) >> shift;
                val = js_sub_string(ctx, str, start, end);
                if (QJS_IsException(val))
                    goto fail;
            }
            if (group_name_ptr && i > 0) {
                if (*group_name_ptr) {
                    if (QJS_DefinePropertyValueStr(ctx, groups, group_name_ptr,
                                                  QJS_DupValue(ctx, val),
                                                  prop_flags) < 0) {
                        QJS_FreeValue(ctx, val);
                        goto fail;
                    }
                }
                group_name_ptr += strlen(group_name_ptr) + 1;
            }
            if (QJS_DefinePropertyValueUint32(ctx, obj, i, val, prop_flags) < 0)
                goto fail;
        }
        if (QJS_DefinePropertyValue(ctx, obj, QJS_ATOM_groups,
                                   groups, prop_flags) < 0)
            goto fail;
        if (QJS_DefinePropertyValue(ctx, obj, QJS_ATOM_index,
                                   QJS_NewInt32(ctx, (capture[0] - str_buf) >> shift), prop_flags) < 0)
            goto fail;
        if (QJS_DefinePropertyValue(ctx, obj, QJS_ATOM_input, str_val, prop_flags) < 0)
            goto fail1;
    }
    js_free(ctx, capture);
    return obj;
fail:
    QJS_FreeValue(ctx, groups);
    QJS_FreeValue(ctx, str_val);
fail1:
    QJS_FreeValue(ctx, obj);
    js_free(ctx, capture);
    return QJS_EXCEPTION;
}

/* delete portions of a string that match a given regex */
static QJSValue QJS_RegExpDelete(QJSContext *ctx, QJSValueConst this_val, QJSValueConst arg)
{
    QJSRegExp *re = js_get_regexp(ctx, this_val, TRUE);
    QJSString *str;
    QJSValue str_val, val;
    uint8_t *re_bytecode;
    int ret;
    uint8_t **capture, *str_buf;
    int capture_count, shift, re_flags;
    int next_src_pos, start, end;
    int64_t last_index;
    StringBuffer b_s, *b = &b_s;

    if (!re)
        return QJS_EXCEPTION;

    string_buffer_init(ctx, b, 0);

    capture = NULL;
    str_val = QJS_ToString(ctx, arg);
    if (QJS_IsException(str_val))
        goto fail;
    str = QJS_VALUE_GET_STRING(str_val);
    re_bytecode = re->bytecode->u.str8;
    re_flags = lre_get_flags(re_bytecode);
    if ((re_flags & (LRE_FLAG_GLOBAL | LRE_FLAG_STICKY)) == 0) {
        last_index = 0;
    } else {
        val = QJS_GetProperty(ctx, this_val, QJS_ATOM_lastIndex);
        if (QJS_IsException(val) || QJS_ToLengthFree(ctx, &last_index, val))
            goto fail;
    }
    capture_count = lre_get_capture_count(re_bytecode);
    if (capture_count > 0) {
        capture = js_malloc(ctx, sizeof(capture[0]) * capture_count * 2);
        if (!capture)
            goto fail;
    }
    shift = str->is_wide_char;
    str_buf = str->u.str8;
    next_src_pos = 0;
    for (;;) {
        if (last_index > str->len)
            break;

        ret = lre_exec(capture, re_bytecode,
                       str_buf, last_index, str->len, shift, ctx);
        if (ret != 1) {
            if (ret >= 0) {
                if (ret == 2 || (re_flags & (LRE_FLAG_GLOBAL | LRE_FLAG_STICKY))) {
                    if (QJS_SetProperty(ctx, this_val, QJS_ATOM_lastIndex,
                                       QJS_NewInt32(ctx, 0)) < 0)
                        goto fail;
                }
            } else {
                QJS_ThrowInternalError(ctx, "out of memory in regexp execution");
                goto fail;
            }
            break;
        }
        start = (capture[0] - str_buf) >> shift;
        end = (capture[1] - str_buf) >> shift;
        last_index = end;
        if (next_src_pos < start) {
            if (string_buffer_concat(b, str, next_src_pos, start))
                goto fail;
        }
        next_src_pos = end;
        if (!(re_flags & LRE_FLAG_GLOBAL)) {
            if (QJS_SetProperty(ctx, this_val, QJS_ATOM_lastIndex,
                               QJS_NewInt32(ctx, end)) < 0)
                goto fail;
            break;
        }
        if (end == start) {
            if (!(re_flags & LRE_FLAG_UTF16) || (unsigned)end >= str->len || !str->is_wide_char) {
                end++;
            } else {
                string_getc(str, &end);
            }
        }
        last_index = end;
    }
    if (string_buffer_concat(b, str, next_src_pos, str->len))
        goto fail;
    QJS_FreeValue(ctx, str_val);
    js_free(ctx, capture);
    return string_buffer_end(b);
fail:
    QJS_FreeValue(ctx, str_val);
    js_free(ctx, capture);
    string_buffer_free(b);
    return QJS_EXCEPTION;
}

static QJSValue QJS_RegExpExec(QJSContext *ctx, QJSValueConst r, QJSValueConst s)
{
    QJSValue method, ret;

    method = QJS_GetProperty(ctx, r, QJS_ATOM_exec);
    if (QJS_IsException(method))
        return method;
    if (QJS_IsFunction(ctx, method)) {
        ret = QJS_CallFree(ctx, method, r, 1, &s);
        if (QJS_IsException(ret))
            return ret;
        if (!QJS_IsObject(ret) && !QJS_IsNull(ret)) {
            QJS_FreeValue(ctx, ret);
            return QJS_ThrowTypeError(ctx, "RegExp exec method must return an object or null");
        }
        return ret;
    }
    QJS_FreeValue(ctx, method);
    return js_regexp_exec(ctx, r, 1, &s);
}

