/* FloatEnv */

static QJSValue js_float_env_constructor(QJSContext *ctx,
                                        QJSValueConst new_target,
                                        int argc, QJSValueConst *argv)
{
    QJSValue obj;
    QJSFloatEnv *fe;
    int64_t prec;
    int flags, rndmode;

    prec = ctx->fp_env.prec;
    flags = ctx->fp_env.flags;
    if (!QJS_IsUndefined(argv[0])) {
        if (QJS_ToInt64Sat(ctx, &prec, argv[0]))
            return QJS_EXCEPTION;
        if (prec < BF_PREC_MIN || prec > BF_PREC_MAX)
            return QJS_ThrowRangeError(ctx, "invalid precision");
        flags = BF_RNDN; /* RNDN, max exponent size, no subnormal */
        if (argc > 1 && !QJS_IsUndefined(argv[1])) {
            if (QJS_ToInt32Sat(ctx, &rndmode, argv[1]))
                return QJS_EXCEPTION;
            if (rndmode < BF_RNDN || rndmode > BF_RNDF)
                return QJS_ThrowRangeError(ctx, "invalid rounding mode");
            flags = rndmode;
        }
    }

    obj = QJS_NewObjectClass(ctx, QJS_CLASS_FLOAT_ENV);
    if (QJS_IsException(obj))
        return QJS_EXCEPTION;
    fe = js_malloc(ctx, sizeof(*fe));
    if (!fe)
        return QJS_EXCEPTION;
    fe->prec = prec;
    fe->flags = flags;
    fe->status = 0;
    QJS_SetOpaque(obj, fe);
    return obj;
}

static void js_float_env_finalizer(QJSRuntime *rt, QJSValue val)
{
    QJSFloatEnv *fe = QJS_GetOpaque(val, QJS_CLASS_FLOAT_ENV);
    js_free_rt(rt, fe);
}

static QJSValue js_float_env_get_prec(QJSContext *ctx, QJSValueConst this_val)
{
    return QJS_NewInt64(ctx, ctx->fp_env.prec);
}

static QJSValue js_float_env_get_expBits(QJSContext *ctx, QJSValueConst this_val)
{
    return QJS_NewInt32(ctx, bf_get_exp_bits(ctx->fp_env.flags));
}

static QJSValue js_float_env_setPrec(QJSContext *ctx,
                                    QJSValueConst this_val,
                                    int argc, QJSValueConst *argv)
{
    QJSValueConst func;
    int exp_bits, flags, saved_flags;
    QJSValue ret;
    limb_t saved_prec;
    int64_t prec;

    func = argv[0];
    if (QJS_ToInt64Sat(ctx, &prec, argv[1]))
        return QJS_EXCEPTION;
    if (prec < BF_PREC_MIN || prec > BF_PREC_MAX)
        return QJS_ThrowRangeError(ctx, "invalid precision");
    exp_bits = BF_EXP_BITS_MAX;

    if (argc > 2 && !QJS_IsUndefined(argv[2])) {
        if (QJS_ToInt32Sat(ctx, &exp_bits, argv[2]))
            return QJS_EXCEPTION;
        if (exp_bits < BF_EXP_BITS_MIN || exp_bits > BF_EXP_BITS_MAX)
            return QJS_ThrowRangeError(ctx, "invalid number of exponent bits");
    }

    flags = BF_RNDN | BF_FLAG_SUBNORMAL | bf_set_exp_bits(exp_bits);

    saved_prec = ctx->fp_env.prec;
    saved_flags = ctx->fp_env.flags;

    ctx->fp_env.prec = prec;
    ctx->fp_env.flags = flags;

    ret = QJS_Call(ctx, func, QJS_UNDEFINED, 0, NULL);
    /* always restore the floating point precision */
    ctx->fp_env.prec = saved_prec;
    ctx->fp_env.flags = saved_flags;
    return ret;
}

#define FE_PREC      (-1)
#define FE_EXP       (-2)
#define FE_RNDMODE   (-3)
#define FE_SUBNORMAL (-4)

static QJSValue js_float_env_proto_get_status(QJSContext *ctx, QJSValueConst this_val, int magic)
{
    QJSFloatEnv *fe;
    fe = QJS_GetOpaque2(ctx, this_val, QJS_CLASS_FLOAT_ENV);
    if (!fe)
        return QJS_EXCEPTION;
    switch(magic) {
    case FE_PREC:
        return QJS_NewInt64(ctx, fe->prec);
    case FE_EXP:
        return QJS_NewInt32(ctx, bf_get_exp_bits(fe->flags));
    case FE_RNDMODE:
        return QJS_NewInt32(ctx, fe->flags & BF_RND_MASK);
    case FE_SUBNORMAL:
        return QJS_NewBool(ctx, (fe->flags & BF_FLAG_SUBNORMAL) != 0);
    default:
        return QJS_NewBool(ctx, (fe->status & magic) != 0);
    }
}

static QJSValue js_float_env_proto_set_status(QJSContext *ctx, QJSValueConst this_val, QJSValueConst val, int magic)
{
    QJSFloatEnv *fe;
    int b;
    int64_t prec;

    fe = QJS_GetOpaque2(ctx, this_val, QJS_CLASS_FLOAT_ENV);
    if (!fe)
        return QJS_EXCEPTION;
    switch(magic) {
    case FE_PREC:
        if (QJS_ToInt64Sat(ctx, &prec, val))
            return QJS_EXCEPTION;
        if (prec < BF_PREC_MIN || prec > BF_PREC_MAX)
            return QJS_ThrowRangeError(ctx, "invalid precision");
        fe->prec = prec;
        break;
    case FE_EXP:
        if (QJS_ToInt32Sat(ctx, &b, val))
            return QJS_EXCEPTION;
        if (b < BF_EXP_BITS_MIN || b > BF_EXP_BITS_MAX)
            return QJS_ThrowRangeError(ctx, "invalid number of exponent bits");
        fe->flags = (fe->flags & ~(BF_EXP_BITS_MASK << BF_EXP_BITS_SHIFT)) |
            bf_set_exp_bits(b);
        break;
    case FE_RNDMODE:
        b = bigfloat_get_rnd_mode(ctx, val);
        if (b < 0)
            return QJS_EXCEPTION;
        fe->flags = (fe->flags & ~BF_RND_MASK) | b;
        break;
    case FE_SUBNORMAL:
        b = QJS_ToBool(ctx, val);
        fe->flags = (fe->flags & ~BF_FLAG_SUBNORMAL) | (b ? BF_FLAG_SUBNORMAL: 0);
        break;
    default:
        b = QJS_ToBool(ctx, val);
        fe->status = (fe->status & ~magic) & ((-b) & magic);
        break;
    }
    return QJS_UNDEFINED;
}

static QJSValue js_float_env_clearStatus(QJSContext *ctx,
                                        QJSValueConst this_val,
                                        int argc, QJSValueConst *argv)
{
    QJSFloatEnv *fe = QJS_GetOpaque2(ctx, this_val, QJS_CLASS_FLOAT_ENV);
    if (!fe)
        return QJS_EXCEPTION;
    fe->status = 0;
    return QJS_UNDEFINED;
}

