static QJSValue js_typed_array_create(QJSContext *ctx, QJSValueConst ctor,
                                     int argc, QJSValueConst *argv)
{
    QJSValue ret;
    int new_len;
    int64_t len;

    ret = QJS_CallConstructor(ctx, ctor, argc, argv);
    if (QJS_IsException(ret))
        return ret;
    /* validate the typed array */
    new_len = js_typed_array_get_length_internal(ctx, ret);
    if (new_len < 0)
        goto fail;
    if (argc == 1) {
        /* ensure that it is large enough */
        if (QJS_ToLengthFree(ctx, &len, QJS_DupValue(ctx, argv[0])))
            goto fail;
        if (new_len < len) {
            QJS_ThrowTypeError(ctx, "TypedArray length is too small");
        fail:
            QJS_FreeValue(ctx, ret);
            return QJS_EXCEPTION;
        }
    }
    return ret;
}

